(function () {
    "use strict";

    const STYLE_ID = "huellitas-guardians-challenge-css";
    const PLAYER_KEY = "huellitasGuardiansPlayer";
    const HISTORY_KEY = "huellitasGuardiansHistory";
    const NICK_KEY = "huellitasGuardiansNickname";
    const SOUND_KEY = "huellitasGuardiansSound";
    const GAME_SECONDS = 90;
    const TARGET = 25;
    const HERO_IMAGE = "data:image/webp;base64,";
    const blockedWords = ["puta", "puto", "mierda", "pendejo", "pendeja", "idiota", "imbecil", "cabron", "cagada"];

    const stations = {
        food: { label: "Comida", icon: "\uD83C\uDF5A", color: "#e7a634" },
        water: { label: "Agua", icon: "\uD83D\uDCA7", color: "#4aaee8" },
        clean: { label: "Limpieza", icon: "\uD83E\uDDFD", color: "#a76be4" },
        rest: { label: "Descanso", icon: "\uD83C\uDF19", color: "#6fae57" },
        check: { label: "Revision", icon: "\uD83E\uDE7A", color: "#e66767" },
        safe: { label: "Zona segura", icon: "\uD83D\uDEE1\uFE0F", color: "#dc9d28" }
    };

    const species = [
        { id: "dog", label: "Perrito", icon: "\uD83D\uDC36", needs: ["food", "water", "rest", "check", "safe"] },
        { id: "cat", label: "Gatito", icon: "\uD83D\uDC31", needs: ["food", "water", "clean", "rest", "safe"] },
        { id: "turtle", label: "Tortuguita", icon: "\uD83D\uDC22", needs: ["water", "check", "safe", "clean"] },
        { id: "bird", label: "Periquito", icon: "\uD83D\uDC26", needs: ["food", "water", "clean", "rest", "safe"] }
    ];

    let game;
    let soundEnabled = localStorage.getItem(SOUND_KEY) !== "false";
    let rankingView = "global";

    function onReady(callback) {
        if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", callback, { once: true });
        else callback();
    }

    function loadStyles() {
        if (document.getElementById(STYLE_ID)) return;
        const link = document.createElement("link");
        link.id = STYLE_ID;
        link.rel = "stylesheet";
        link.href = "huellitas-guardians-challenge.css?v=20260630-guardians-v1";
        document.head.appendChild(link);
    }

    function safeNickname(value) {
        return String(value || "")
            .replace(/<[^>]*>/g, "")
            .replace(/[<>\x60{}]/g, "")
            .replace(/[^\p{L}\p{N} _-]/gu, "")
            .replace(/\s+/g, " ")
            .trim()
            .slice(0, 12);
    }

    function blockedNickname(value) {
        const compact = String(value || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, "");
        return blockedWords.some(function (word) { return compact.indexOf(word) >= 0; });
    }

    function playerId() {
        let id = localStorage.getItem(PLAYER_KEY);
        if (!id) {
            id = "guardian-" + Date.now().toString(36) + "-" + Math.random().toString(36).slice(2, 12);
            localStorage.setItem(PLAYER_KEY, id);
        }
        return id;
    }

    function personalPetName() {
        try {
            if (typeof state !== "undefined" && state && state.name) return String(state.name).slice(0, 18);
        } catch (error) {}
        return "Tu mascota";
    }

    function personalPetMarkup(extraClass) {
        try {
            if (typeof getMiniPetSpriteMarkup === "function") return getMiniPetSpriteMarkup(extraClass || "");
        } catch (error) {}
        return '<span class="guardian-pet-fallback" aria-label="Perrito personalizado"></span>';
    }

    function freshGame() {
        return {
            running: false,
            ended: false,
            time: GAME_SECONDS,
            attended: 0,
            errors: 0,
            combo: 0,
            maxCombo: 0,
            score: 0,
            wellbeing: 78,
            security: 84,
            reputation: 76,
            patients: [],
            selectedId: "",
            nextId: 1,
            timer: 0,
            savedHistory: false,
            startedAt: 0,
            rank: "Ayudante de Patitas"
        };
    }

    function buildMarkup(panel) {
        panel.classList.add("guardians-premium");
        panel.innerHTML = [
            '<div class="guardian-premium-layout">',
                '<section class="guardian-main-card">',
                    '<header class="guardian-hero">',
                        '<div class="guardian-hero-copy">',
                            '<span class="guardian-kicker">CENTRO DE RESCATE</span>',
                            '<h2>Guardianes <em>de Patitas</em></h2>',
                            '<p>Organiza el refugio y lleva cada mascota a la estacion que necesita antes de que se agote el tiempo.</p>',
                            '<div class="guardian-companion">',
                                '<span class="guardian-companion-pet">' + personalPetMarkup("guardian-helper-sprite") + '</span>',
                                '<span><small>Tu companero guardian</small><strong id="guardianCompanionName"></strong></span>',
                                '<b id="guardianSpeech">Listos para ayudar.</b>',
                            '</div>',
                        '</div>',
                        '<figure class="guardian-hero-visual"><img src="' + HERO_IMAGE + '" alt="Equipo de animales guardianes" draggable="false"></figure>',
                    '</header>',
                    '<div class="guardian-shelter-bars" aria-label="Estado general del refugio">',
                        '<div><span><b>\u2764\uFE0F</b> Bienestar <strong id="guardianWellbeingText">78%</strong></span><i><u id="guardianWellbeingBar"></u></i></div>',
                        '<div><span><b>\uD83D\uDEE1\uFE0F</b> Seguridad <strong id="guardianSecurityText">84%</strong></span><i><u id="guardianSecurityBar"></u></i></div>',
                        '<div><span><b>\u2B50</b> Reputacion <strong id="guardianReputationText">76%</strong></span><i><u id="guardianReputationBar"></u></i></div>',
                    '</div>',
                    '<div class="guardian-toolbar">',
                        '<div><span>\u23F1 Tiempo</span><strong id="guardianClock">01:30</strong></div>',
                        '<div><span>\uD83D\uDC3E Atendidas</span><strong id="guardianAttended">0 / 25</strong></div>',
                        '<div><span>\u26A1 Combo</span><strong id="guardianCombo">x0</strong></div>',
                        '<div><span>\u2B50 Puntos</span><strong id="guardianPoints">0</strong></div>',
                        '<button id="guardianSound" type="button" aria-label="Activar o desactivar sonido"></button>',
                    '</div>',
                    '<div class="guardian-rescue-stage" id="guardianStage" data-state="idle">',
                        '<div class="guardian-stage-heading"><span>REFUGIO HUELLITAS</span><strong id="guardianStageStatus">Elige iniciar para abrir el centro.</strong></div>',
                        '<div class="guardian-patient-zone">',
                            '<div class="guardian-arrivals" id="guardianArrivals"></div>',
                            '<div class="guardian-empty" id="guardianEmpty"><span>\uD83C\uDFE1</span><strong>Centro preparado</strong><small>Las mascotas apareceran aqui.</small></div>',
                        '</div>',
                        '<div class="guardian-stations" id="guardianStations"></div>',
                    '</div>',
                    '<div class="guardian-controls">',
                        '<button class="guardian-start" id="guardianStart" type="button">\uD83D\uDC3E Abrir centro de rescate</button>',
                        '<button class="guardian-hint" id="guardianHint" type="button">\uD83D\uDCA1 Mostrar estacion</button>',
                    '</div>',
                    '<p class="guardian-help">Toca una mascota y despues su estacion. En computadora tambien puedes arrastrarla.</p>',
                '</section>',
                '<aside class="guardian-ranking-card" id="guardianRanking">',
                    '<div class="guardian-ranking-tabs">',
                        '<button class="active" type="button" data-guardian-view="global">\uD83C\uDFC6 Mejores</button>',
                        '<button type="button" data-guardian-view="history">\uD83D\uDCCB Mis rescates</button>',
                    '</div>',
                    '<header class="guardian-ranking-heading"><div><span>CLASIFICACION</span><h3>Mejores Guardianes</h3></div><button id="guardianRefresh" type="button" title="Actualizar">\u21BB</button></header>',
                    '<p class="guardian-ranking-state" id="guardianRankingState">Preparando refugio...</p>',
                    '<div class="guardian-ranking-table" id="guardianRankingTable"></div>',
                    '<div class="guardian-current-score" id="guardianCurrentScore" hidden></div>',
                    '<footer class="guardian-ranking-footer"><span>Solo se guarda un apodo, nunca datos personales.</span><button id="guardianClearHistory" type="button">Borrar historial</button></footer>',
                '</aside>',
            '</div>',
            '<div class="guardian-result-modal" id="guardianResultModal" hidden>',
                '<div class="guardian-result-backdrop" data-guardian-close></div>',
                '<section class="guardian-result-card" role="dialog" aria-modal="true" aria-labelledby="guardianResultTitle">',
                    '<button class="guardian-result-close" type="button" data-guardian-close aria-label="Cerrar">&times;</button>',
                    '<div class="guardian-result-visual"><img src="' + HERO_IMAGE + '" alt="" draggable="false"><span>\uD83C\uDFC6</span></div>',
                    '<span class="guardian-result-kicker">CENTRO ESTABLE</span>',
                    '<h2 id="guardianResultTitle">\u00a1Rescate completado!</h2>',
                    '<p id="guardianResultRank"></p>',
                    '<div class="guardian-result-stats">',
                        '<div><span>Mascotas</span><strong id="guardianResultAttended">0</strong></div>',
                        '<div><span>Puntos</span><strong id="guardianResultPoints">0</strong></div>',
                        '<div><span>Errores</span><strong id="guardianResultErrors">0</strong></div>',
                        '<div><span>Bienestar</span><strong id="guardianResultWellbeing">0%</strong></div>',
                        '<div><span>Seguridad</span><strong id="guardianResultSecurity">0%</strong></div>',
                        '<div><span>Combo max.</span><strong id="guardianResultCombo">x0</strong></div>',
                    '</div>',
                    '<label class="guardian-nickname">Apodo para guardar el resultado<span><input id="guardianNickname" maxlength="12" autocomplete="nickname" placeholder="Jugador"><b id="guardianNicknameCount">0/12</b></span></label>',
                    '<p class="guardian-save-state" id="guardianSaveState"></p>',
                    '<div class="guardian-result-actions">',
                        '<button class="guardian-save-result" id="guardianSaveResult" type="button">\uD83C\uDFC6 Guardar resultado</button>',
                        '<button id="guardianPlayAgain" type="button">\u21BB Jugar otra vez</button>',
                        '<button id="guardianViewRanking" type="button">Ver clasificacion</button>',
                    '</div>',
                '</section>',
            '</div>'
        ].join("");

        document.getElementById("guardianCompanionName").textContent = personalPetName();
        buildStations();
    }

    function elements() {
        return {
            stage: document.getElementById("guardianStage"),
            arrivals: document.getElementById("guardianArrivals"),
            empty: document.getElementById("guardianEmpty"),
            speech: document.getElementById("guardianSpeech"),
            clock: document.getElementById("guardianClock"),
            attended: document.getElementById("guardianAttended"),
            combo: document.getElementById("guardianCombo"),
            points: document.getElementById("guardianPoints"),
            start: document.getElementById("guardianStart"),
            hint: document.getElementById("guardianHint"),
            sound: document.getElementById("guardianSound"),
            status: document.getElementById("guardianStageStatus"),
            rankingTable: document.getElementById("guardianRankingTable"),
            rankingState: document.getElementById("guardianRankingState"),
            currentScore: document.getElementById("guardianCurrentScore"),
            ranking: document.getElementById("guardianRanking"),
            modal: document.getElementById("guardianResultModal"),
            nickname: document.getElementById("guardianNickname"),
            nicknameCount: document.getElementById("guardianNicknameCount"),
            saveState: document.getElementById("guardianSaveState")
        };
    }

    function buildStations() {
        const target = document.getElementById("guardianStations");
        Object.keys(stations).forEach(function (id) {
            const station = stations[id];
            const button = document.createElement("button");
            button.type = "button";
            button.className = "guardian-station";
            button.dataset.station = id;
            button.style.setProperty("--station", station.color);
            button.innerHTML = '<span>' + station.icon + '</span><strong>' + station.label + '</strong><small>Disponible</small>';
            button.addEventListener("click", function () { chooseStation(id); });
            button.addEventListener("dragover", function (event) { event.preventDefault(); });
            button.addEventListener("drop", function (event) {
                event.preventDefault();
                const patientId = event.dataTransfer.getData("text/plain");
                if (patientId) game.selectedId = patientId;
                chooseStation(id);
            });
            target.appendChild(button);
        });
    }

    function formatTime(seconds) {
        const safe = Math.max(0, seconds);
        return String(Math.floor(safe / 60)).padStart(2, "0") + ":" + String(safe % 60).padStart(2, "0");
    }

    function clamp(value) {
        return Math.max(0, Math.min(100, Math.round(value)));
    }

    function rankForScore(score) {
        if (score >= 4000) return "Guardian Legendario";
        if (score >= 2800) return "Guardian Experto";
        if (score >= 1700) return "Protector del Refugio";
        if (score >= 800) return "Cuidador Responsable";
        return "Ayudante de Patitas";
    }

    function randomPatient() {
        const animal = species[Math.floor(Math.random() * species.length)];
        const need = animal.needs[Math.floor(Math.random() * animal.needs.length)];
        const life = Math.max(7, 14 - Math.floor(game.attended / 5));
        return {
            id: "patient-" + game.nextId++,
            species: animal.id,
            label: animal.label,
            icon: animal.icon,
            need,
            expiresAt: Date.now() + life * 1000,
            life
        };
    }

    function maxPatients() {
        if (game.attended >= 14) return 3;
        if (game.attended >= 6) return 2;
        return 1;
    }

    function fillPatients() {
        if (!game.running) return;
        while (game.patients.length < maxPatients()) game.patients.push(randomPatient());
        if (!game.selectedId && game.patients[0]) game.selectedId = game.patients[0].id;
        renderPatients();
    }

    function renderPatients() {
        const el = elements();
        el.arrivals.innerHTML = "";
        el.empty.hidden = game.patients.length > 0;
        game.patients.forEach(function (patient) {
            const station = stations[patient.need];
            const remaining = Math.max(0, patient.expiresAt - Date.now());
            const ratio = Math.max(0, Math.min(100, remaining / (patient.life * 1000) * 100));
            const button = document.createElement("button");
            button.type = "button";
            button.className = "guardian-patient" + (game.selectedId === patient.id ? " selected" : "");
            button.dataset.patient = patient.id;
            button.draggable = true;
            button.style.setProperty("--need", station.color);
            button.innerHTML = [
                '<span class="guardian-patient-icon">' + patient.icon + '</span>',
                '<span class="guardian-need-bubble">' + station.icon + '<small>' + station.label + '</small></span>',
                '<strong>' + patient.label + '</strong>',
                '<i><u style="width:' + ratio + '%"></u></i>'
            ].join("");
            button.addEventListener("click", function () {
                game.selectedId = patient.id;
                renderPatients();
                speak(patient.label + " necesita " + station.label.toLowerCase() + ".");
            });
            button.addEventListener("dragstart", function (event) {
                game.selectedId = patient.id;
                event.dataTransfer.setData("text/plain", patient.id);
            });
            el.arrivals.appendChild(button);
        });
    }

    function renderStats() {
        const el = elements();
        el.clock.textContent = formatTime(game.time);
        el.attended.textContent = game.attended + " / " + TARGET;
        el.combo.textContent = "x" + game.combo;
        el.points.textContent = game.score.toLocaleString("es-MX");
        [
            ["Wellbeing", game.wellbeing],
            ["Security", game.security],
            ["Reputation", game.reputation]
        ].forEach(function (entry) {
            const text = document.getElementById("guardian" + entry[0] + "Text");
            const bar = document.getElementById("guardian" + entry[0] + "Bar");
            text.textContent = clamp(entry[1]) + "%";
            bar.style.width = clamp(entry[1]) + "%";
        });
    }

    function speak(message, mood) {
        const el = elements();
        el.speech.textContent = message;
        el.speech.classList.remove("pop");
        void el.speech.offsetWidth;
        el.speech.classList.add("pop");
        el.stage.dataset.state = mood || "active";
    }

    function beep(kind) {
        if (!soundEnabled) return;
        try {
            const AudioContext = window.AudioContext || window.webkitAudioContext;
            const context = new AudioContext();
            const oscillator = context.createOscillator();
            const gain = context.createGain();
            oscillator.type = kind === "bad" ? "sawtooth" : "sine";
            oscillator.frequency.value = kind === "bad" ? 170 : kind === "combo" ? 740 : 480;
            gain.gain.setValueAtTime(.08, context.currentTime);
            gain.gain.exponentialRampToValueAtTime(.001, context.currentTime + .16);
            oscillator.connect(gain).connect(context.destination);
            oscillator.start();
            oscillator.stop(context.currentTime + .17);
        } catch (error) {}
    }

    function renderSound() {
        elements().sound.textContent = soundEnabled ? "\uD83D\uDD0A Sonido" : "\uD83D\uDD07 Sonido";
        elements().sound.setAttribute("aria-pressed", soundEnabled ? "true" : "false");
    }

    function chooseStation(stationId) {
        if (!game.running) return;
        const patient = game.patients.find(function (item) { return item.id === game.selectedId; });
        if (!patient) {
            speak("Primero elige una mascota.", "idle");
            return;
        }
        const stationButton = document.querySelector('[data-station="' + stationId + '"]');
        if (patient.need === stationId) {
            const speed = Math.max(0, patient.expiresAt - Date.now());
            game.combo += 1;
            game.maxCombo = Math.max(game.maxCombo, game.combo);
            game.attended += 1;
            game.score += 105 + Math.round(speed / 260) + game.combo * 12;
            game.wellbeing = clamp(game.wellbeing + 3);
            game.security = clamp(game.security + 1.5);
            game.reputation = clamp(game.reputation + 3);
            game.patients = game.patients.filter(function (item) { return item.id !== patient.id; });
            game.selectedId = "";
            stationButton.classList.add("success");
            stationButton.querySelector("small").textContent = "Atendiendo...";
            setTimeout(function () {
                stationButton.classList.remove("success");
                stationButton.querySelector("small").textContent = "Disponible";
            }, 700);
            speak(game.combo >= 5 ? "\u00a1Combo de rescate x" + game.combo + "!" : "\u00a1" + patient.label + " atendido!", "correct");
            beep(game.combo >= 5 ? "combo" : "good");
            if (game.attended >= TARGET) {
                endGame("target");
                return;
            }
            fillPatients();
        } else {
            game.errors += 1;
            game.combo = 0;
            game.score = Math.max(0, game.score - 35);
            game.security = clamp(game.security - 6);
            game.reputation = clamp(game.reputation - 5);
            stationButton.classList.add("error");
            setTimeout(function () { stationButton.classList.remove("error"); }, 420);
            speak("Esa no es la estacion. Busca " + stations[patient.need].label + ".", "error");
            beep("bad");
        }
        renderStats();
    }

    function expirePatients() {
        const now = Date.now();
        const expired = game.patients.filter(function (patient) { return patient.expiresAt <= now; });
        if (!expired.length) return;
        expired.forEach(function () {
            game.errors += 1;
            game.combo = 0;
            game.wellbeing = clamp(game.wellbeing - 7);
            game.reputation = clamp(game.reputation - 3);
        });
        game.patients = game.patients.filter(function (patient) { return patient.expiresAt > now; });
        game.selectedId = "";
        speak("Una mascota espero demasiado. Recuperemos el ritmo.", "error");
        beep("bad");
        fillPatients();
    }

    function tick() {
        if (!game.running) return;
        game.time -= 1;
        expirePatients();
        renderPatients();
        renderStats();
        if (game.time <= 0 || game.wellbeing <= 0 || game.security <= 0) endGame("time");
    }

    function startGame() {
        if (game.timer) clearInterval(game.timer);
        game = freshGame();
        game.running = true;
        game.startedAt = Date.now();
        const el = elements();
        el.stage.dataset.state = "active";
        el.status.textContent = "Atiende rapido y protege el refugio.";
        el.start.textContent = "\u21BB Reiniciar rescate";
        el.modal.hidden = true;
        fillPatients();
        renderStats();
        speak("\u00a1El centro esta abierto, " + personalPetName() + "!", "active");
        game.timer = setInterval(tick, 1000);
    }

    function resultPayload() {
        return {
            nickname: safeNickname(elements().nickname.value) || "Jugador",
            anonymousId: playerId(),
            score: game.score,
            attended: game.attended,
            errors: game.errors,
            wellbeing: clamp(game.wellbeing),
            security: clamp(game.security),
            reputation: clamp(game.reputation),
            combo: game.maxCombo,
            duration: Math.max(1, Math.round((Date.now() - game.startedAt) / 1000))
        };
    }

    function saveHistory() {
        if (game.savedHistory) return;
        game.savedHistory = true;
        let history = [];
        try { history = JSON.parse(localStorage.getItem(HISTORY_KEY)) || []; } catch (error) {}
        history.unshift(Object.assign({ date: new Date().toISOString(), rank: game.rank }, resultPayload()));
        localStorage.setItem(HISTORY_KEY, JSON.stringify(history.slice(0, 20)));
    }

    function endGame(reason) {
        if (!game.running || game.ended) return;
        game.running = false;
        game.ended = true;
        if (game.timer) clearInterval(game.timer);
        game.timer = 0;
        game.rank = rankForScore(game.score);
        saveHistory();
        renderStats();
        elements().status.textContent = reason === "target" ? "Centro completo: 25 mascotas atendidas." : "Turno terminado.";
        document.getElementById("guardianResultAttended").textContent = game.attended;
        document.getElementById("guardianResultPoints").textContent = game.score.toLocaleString("es-MX");
        document.getElementById("guardianResultErrors").textContent = game.errors;
        document.getElementById("guardianResultWellbeing").textContent = clamp(game.wellbeing) + "%";
        document.getElementById("guardianResultSecurity").textContent = clamp(game.security) + "%";
        document.getElementById("guardianResultCombo").textContent = "x" + game.maxCombo;
        document.getElementById("guardianResultRank").textContent = game.rank + " - " + game.attended + " rescates";
        const nickname = localStorage.getItem(NICK_KEY) || "";
        elements().nickname.value = nickname;
        elements().nicknameCount.textContent = nickname.length + "/12";
        elements().saveState.textContent = "";
        elements().modal.hidden = false;
        document.body.classList.add("guardian-modal-open");
        beep("combo");
    }

    function closeModal() {
        elements().modal.hidden = true;
        document.body.classList.remove("guardian-modal-open");
    }

    function showHint() {
        if (!game.running) return;
        const patient = game.patients.find(function (item) { return item.id === game.selectedId; }) || game.patients[0];
        if (!patient) return;
        game.selectedId = patient.id;
        const button = document.querySelector('[data-station="' + patient.need + '"]');
        button.classList.add("hint");
        setTimeout(function () { button.classList.remove("hint"); }, 1100);
        speak("Pista: " + stations[patient.need].label + ".", "active");
        renderPatients();
    }

    async function apiRequest(path, options) {
        if (!window.huellitasApi || !window.huellitasApi.enabled || typeof window.huellitasApi.request !== "function") {
            throw new Error("La clasificacion global no esta disponible.");
        }
        const requestOptions = Object.assign({}, options || {});
        requestOptions.headers = Object.assign({}, requestOptions.headers || {}, { "X-Huellitas-Player": playerId() });
        return window.huellitasApi.request(path, requestOptions);
    }

    function addCell(row, text, className) {
        const span = document.createElement("span");
        span.className = className || "";
        span.textContent = text;
        row.appendChild(span);
    }

    function renderRanking(scores) {
        const table = elements().rankingTable;
        table.innerHTML = "";
        const head = document.createElement("div");
        head.className = "guardian-rank-row guardian-rank-head";
        ["#", "Jugador", "Puntos", "Masc.", "Err.", "Combo"].forEach(function (item) { addCell(head, item); });
        table.appendChild(head);
        if (!scores || !scores.length) {
            table.innerHTML += '<p class="guardian-ranking-empty">Completa un rescate para inaugurar la clasificacion.</p>';
            return;
        }
        scores.forEach(function (item) {
            const row = document.createElement("div");
            row.className = "guardian-rank-row rank-" + item.rank + (item.current ? " is-current" : "");
            addCell(row, item.rank);
            addCell(row, item.nickname, "rank-player");
            addCell(row, Number(item.score || 0).toLocaleString("es-MX"));
            addCell(row, item.attended);
            addCell(row, item.errors);
            addCell(row, "x" + item.combo);
            table.appendChild(row);
        });
    }

    function renderHistory() {
        let history = [];
        try { history = JSON.parse(localStorage.getItem(HISTORY_KEY)) || []; } catch (error) {}
        const table = elements().rankingTable;
        table.innerHTML = "";
        if (!history.length) {
            table.innerHTML = '<p class="guardian-ranking-empty">Tus rescates apareceran aqui.</p>';
            return;
        }
        history.forEach(function (item) {
            const row = document.createElement("div");
            row.className = "guardian-history-row";
            addCell(row, new Date(item.date).toLocaleDateString("es-MX"));
            addCell(row, item.rank, "rank-player");
            addCell(row, Number(item.score || 0).toLocaleString("es-MX"));
            addCell(row, item.attended + " mascotas");
            addCell(row, "x" + item.combo);
            table.appendChild(row);
        });
        elements().rankingState.textContent = history.length + " rescates guardados en este dispositivo.";
    }

    async function loadRanking() {
        if (rankingView === "history") {
            renderHistory();
            return;
        }
        elements().rankingState.textContent = "Actualizando clasificacion...";
        try {
            const data = await apiRequest("/api/guardians-ranking");
            renderRanking(data.scores || []);
            elements().rankingState.textContent = data.scores && data.scores.length ? "Ranking global del refugio." : "Aun no hay resultados.";
            if (data.current) {
                elements().currentScore.hidden = false;
                elements().currentScore.innerHTML = '<span>Tu mejor resultado</span><strong>#' + data.current.rank + ' - ' + Number(data.current.score).toLocaleString("es-MX") + ' puntos</strong>';
            } else elements().currentScore.hidden = true;
        } catch (error) {
            elements().rankingState.textContent = error.message;
            renderRanking([]);
        }
    }

    async function saveResult() {
        const nickname = safeNickname(elements().nickname.value) || "Jugador";
        if (blockedNickname(nickname)) {
            elements().saveState.textContent = "Elige otro apodo.";
            elements().nickname.focus();
            return;
        }
        localStorage.setItem(NICK_KEY, nickname);
        const payload = resultPayload();
        payload.nickname = nickname;
        elements().saveState.textContent = "Guardando...";
        try {
            const data = await apiRequest("/api/guardians-ranking", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });
            elements().saveState.textContent = data.savedBest === false ? "Resultado recibido. Tu mejor marca sigue arriba." : "\u00a1Resultado guardado!";
            renderRanking(data.scores || []);
            rankingView = "global";
        } catch (error) {
            elements().saveState.textContent = error.message;
        }
    }

    function setRankingView(view) {
        rankingView = view === "history" ? "history" : "global";
        document.querySelectorAll("[data-guardian-view]").forEach(function (button) {
            button.classList.toggle("active", button.dataset.guardianView === rankingView);
        });
        loadRanking();
    }

    function bindEvents() {
        elements().start.addEventListener("click", startGame);
        elements().hint.addEventListener("click", showHint);
        elements().sound.addEventListener("click", function () {
            soundEnabled = !soundEnabled;
            localStorage.setItem(SOUND_KEY, String(soundEnabled));
            renderSound();
        });
        document.querySelectorAll("[data-guardian-view]").forEach(function (button) {
            button.addEventListener("click", function () { setRankingView(button.dataset.guardianView); });
        });
        document.getElementById("guardianRefresh").addEventListener("click", loadRanking);
        document.getElementById("guardianClearHistory").addEventListener("click", function () {
            localStorage.removeItem(HISTORY_KEY);
            if (rankingView === "history") renderHistory();
        });
        document.querySelectorAll("[data-guardian-close]").forEach(function (button) { button.addEventListener("click", closeModal); });
        document.getElementById("guardianPlayAgain").addEventListener("click", function () { closeModal(); startGame(); });
        document.getElementById("guardianViewRanking").addEventListener("click", function () {
            closeModal();
            setRankingView("global");
            elements().ranking.scrollIntoView({ behavior: "smooth", block: "center" });
        });
        document.getElementById("guardianSaveResult").addEventListener("click", saveResult);
        elements().nickname.addEventListener("input", function () {
            elements().nicknameCount.textContent = safeNickname(elements().nickname.value).length + "/12";
            elements().saveState.textContent = "";
        });
        document.addEventListener("keydown", function (event) {
            if (event.key === "Escape" && !elements().modal.hidden) closeModal();
        });
    }

    function enhance() {
        const panel = document.getElementById("game-guardians");
        if (!panel || panel.dataset.guardiansPremium === "true") return;
        panel.dataset.guardiansPremium = "true";
        loadStyles();
        buildMarkup(panel);
        game = freshGame();
        renderSound();
        renderStats();
        renderPatients();
        bindEvents();
        loadRanking();
        window.iniciarGuardianesPatitas = startGame;
    }

    onReady(enhance);
})();
